INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (1, 5, 1, 1, '김순자 어르신 감기 증상 및 약 처방 관련 문의', '안녕하세요. 최근 일교차가 커져서 아침저녁으로 방이 쌀쌀한 것 같습니다. 혹시 순자 어르신께서 감기 기운이나 기침을 하지는 않으시는지 조심스럽게 여쭤봅니다. 필요하다면 가정에서 상비약을 가지고 방문하겠습니다.', 'HEALTH', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.92, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'READ', 1, '2026-05-04 16:30:00+00', NULL, '2026-05-04 14:00:00+00', '2026-05-04 14:00:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (2, 6, 2, 1, '어버이날 주말 대면 면회 신청합니다', '어버이날을 맞아 5월 9일 토요일 오후 2시경에 아버님 대면 면회를 신청하고 싶습니다. 참여 가능 인원은 총 3명(보호자 부부, 자녀 1명)입니다. 예약 확인 및 가능 여부를 답변해 주시면 감사하겠습니다.', 'VISIT', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.92, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'READ', 2, '2026-05-06 11:00:00+00', NULL, '2026-05-06 09:30:00+00', '2026-05-06 09:30:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (3, 7, 3, 1, '박정호 어르신 식사 섭취 관련 건의사항', '아버님께서 치아 통증이 있으신지 최근 밥을 절반만 드셨다는 알림장을 받았습니다. 식단 제공 시 반찬류나 고기류를 아주 잘게 다지거나 부드러운 형태로 제공해 주실 수 있으신가요? 부탁드리겠습니다.', 'MEAL', 0.92, '{"MEAL": 0.92, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'READ', 1, '2026-05-11 14:20:00+00', NULL, '2026-05-11 10:15:00+00', '2026-05-11 10:15:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (4, 5, 1, 1, '5월 장기요양 본인부담금 청구서 및 영수증 재발급 요청', '안녕하세요. 계좌이체 내역과 대조해 보고 싶은 영수증 내역이 있어 5월 청구 영수증을 메일로 받아보고 싶습니다. 이메일 주소는 boram@family.kr 입니다. 확인 부탁드립니다.', 'ADMIN_AFFAIRS', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.92}', 'SUCCESS', 'READ', 2, '2026-05-14 13:00:00+00', NULL, '2026-05-14 11:00:00+00', '2026-05-14 11:00:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (5, 6, 2, 1, '석가탄신일 연휴 비대면 화상면회 희망', '석가탄신일인 5월 24일에 가족들이 직접 갈 수가 없어서요. 영상통화로라도 아버님 얼굴을 뵙고 인사를 나누고 싶습니다. 일요일 오후 3시~4시 사이에 10분 정도 연결 가능할지 문의합니다.', 'VISIT', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.92, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'READ', 2, '2026-05-20 18:00:00+00', NULL, '2026-05-20 16:20:00+00', '2026-05-20 16:20:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (6, 7, 3, 1, '박정호 어르신 정기 외래 진료 동행 안내 건', '다음 주 목요일인 5월 28일에 서울대학병원 비뇨기과 예약이 있어 외출해야 합니다. 사설 구급차는 예약해 두었으며, 당일 오전 9시 30분에 모시러 갈 예정입니다. 외출 준비 및 차트 서류 챙기기 부탁드립니다.', 'HEALTH', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.92, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'READ', 1, '2026-05-22 11:30:00+00', NULL, '2026-05-22 10:00:00+00', '2026-05-22 10:00:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (7, 5, 1, 1, '김순자 어르신 개인 당뇨 간식 제재 요청', '최근 요양원 프로그램에서 빵과 과자가 간식으로 나오는 것을 어르신께서 너무 기분 좋게 드셨다는 소식을 보았습니다. 당뇨를 앓고 계셔 혈당 급상승 우려가 있습니다. 탄수화물류 간식 섭취 비중을 줄여주실 수 있는지요.', 'MEAL', 0.92, '{"MEAL": 0.92, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'READ', 1, '2026-05-25 16:10:00+00', NULL, '2026-05-25 14:45:00+00', '2026-05-25 14:45:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (8, 6, 2, 1, '주중 퇴근 후 야간 면회(19시 이후) 규정 문의', '주말에는 급한 해외 출장이 잡혀 방문하기 힘듭니다. 혹시 평일 퇴근 후 19시경에 짧게 면회하는 것이 요양원 내부 규정상 허용되는지 여쭤보고 싶습니다. 불가피한 상황이라 답변 부탁드립니다.', 'VISIT', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.92, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'UNREAD', NULL, NULL, NULL, '2026-05-27 18:00:00+00', '2026-05-27 18:00:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (9, 5, 1, 1, '순자 어르신 세탁물(카디건) 분실 확인 건', '가족들이 지난주 사드렸던 진한 핑크색 꽃무늬 봄 카디건이 세탁실에서 섞였는지 장롱에 보이지 않는다고 하시네요. 세탁실 바구니나 다른 어르신 옷장으로 잘못 가지 않았는지 한 번만 수색해 봐주세요. 감사합니다.', 'OTHER', 0.92, '{"MEAL": 0.02, "OTHER": 0.92, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'UNREAD', NULL, NULL, NULL, '2026-05-28 10:00:00+00', '2026-05-28 10:00:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (10, 7, 3, 1, '욕창 예방 전용 에어 매트리스 설치 여부', '아버님께서 와상 상태로 침상 생활 비중이 아주 높다 보니 피부 욕창이 크게 염려됩니다. 필요시 개인용 욕창 매트리스를 구매해서 병실 침대에 설치하는 것이 반입 및 전기 사용 허용 규정에 어긋나지 않는지 알려주십시오.', 'HEALTH', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.92, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'UNREAD', NULL, NULL, NULL, '2026-05-29 13:00:00+00', '2026-05-29 13:00:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (11, 6, 2, 1, '6월 둘째 주 주말 예약 면회 신청', '6월 13일 토요일 오전 11시에 대면 면회 2명 신청하고 싶습니다. 시간이 많이 남아있지만 인원이 마감되기 전에 미리 등록하고자 하오니 예약 조치 후 확인 부탁드립니다.', 'VISIT', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.92, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.02}', 'SUCCESS', 'UNREAD', NULL, NULL, NULL, '2026-05-30 10:00:00+00', '2026-05-30 10:00:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (12, 5, 1, 1, '장기요양 세액공제 증명원 팩스 전송 요청', '직장 연말정산 보정 기간이라 요양원 납부 확인 내역이 필요해졌습니다. 회사 팩스 번호인 02-9999-8888 번으로 증명원을 한 부만 팩스 송부해 주실 수 있을까요? 늦어도 다음 주 월요일까지 부탁드립니다.', 'ADMIN_AFFAIRS', 0.92, '{"MEAL": 0.02, "OTHER": 0.02, "VISIT": 0.02, "HEALTH": 0.02, "ADMIN_AFFAIRS": 0.92}', 'SUCCESS', 'UNREAD', NULL, NULL, NULL, '2026-06-01 09:30:00+00', '2026-06-01 09:30:00+00', NULL);
INSERT INTO public.inquiry (id, guardian_user_id, resident_id, facility_id, title, content, category, confidence, classification_scores, classification_status, status, read_by, read_at, answer_read_at, created_at, updated_at, deleted_at) VALUES (13, 5, 1, 1, '어르신 간식 및 음료 제공 관련 문의', '최근 요양원 간식 제공 내역을 보니 어르신께서 단 음료를 자주 드시는 것으로 확인되었습니다. 혈압과 혈당 관리가 필요한 상태여서 음료 섭취가 다소 걱정됩니다. 가능하다면 당 함량이 낮은 음료나 물, 차 위주로 제공해 주실 수 있는지 문의드립니다.', 'MEAL', 0.7, '{"MEAL": 0.7, "OTHER": 0.0, "VISIT": 0.0, "HEALTH": 0.3, "ADMIN_AFFAIRS": 0.0}', 'SUCCESS', 'UNREAD', NULL, NULL, NULL, '2026-06-01 11:27:15.150087+00', '2026-06-01 11:27:15.150087+00', NULL);
