INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (1, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 5, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 6, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-04 17:00:00+00', '2026-05-04 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (2, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 5, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 6, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-04 17:10:00+00', '2026-05-04 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (3, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 5, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 6, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-04 17:20:00+00', '2026-05-04 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (4, 1, 1, NULL, 1, '{"meal": "LITTLE", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 7, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 8, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-05 17:00:00+00', '2026-05-05 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (5, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 7, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 8, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-05 17:10:00+00', '2026-05-05 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (6, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "NEEDS_OBSERVATION", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 7, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 8, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-05 17:20:00+00', '2026-05-05 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (7, 1, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 9, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 10, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-06 17:00:00+00', '2026-05-06 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (8, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 9, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 10, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-06 17:10:00+00', '2026-05-06 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (9, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 9, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 10, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-06 17:20:00+00', '2026-05-06 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (10, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 11, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 12, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-07 17:00:00+00', '2026-05-07 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (11, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 11, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 12, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-07 17:10:00+00', '2026-05-07 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (12, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 11, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 12, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-07 17:20:00+00', '2026-05-07 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (13, 1, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 13, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 14, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-08 17:00:00+00', '2026-05-08 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (14, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 13, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 14, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-08 17:10:00+00', '2026-05-08 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (15, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 13, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 14, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-08 17:20:00+00', '2026-05-08 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (16, 1, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 15, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-09 17:00:00+00', '2026-05-09 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (17, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 15, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-09 17:10:00+00', '2026-05-09 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (18, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 15, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-09 17:20:00+00', '2026-05-09 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (19, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 16, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-10 17:00:00+00', '2026-05-10 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (20, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 16, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-10 17:10:00+00', '2026-05-10 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (21, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "NEEDS_OBSERVATION", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 16, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-10 17:20:00+00', '2026-05-10 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (22, 1, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 17, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 18, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-11 17:00:00+00', '2026-05-11 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (23, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 17, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 18, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-11 17:10:00+00', '2026-05-11 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (24, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 17, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 18, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-11 17:20:00+00', '2026-05-11 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (25, 1, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 19, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 20, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-12 17:00:00+00', '2026-05-12 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (26, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "NORMAL", "health": "NORMAL", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 19, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 20, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-12 17:10:00+00', '2026-05-12 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (27, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 19, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 20, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-12 17:20:00+00', '2026-05-12 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (28, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 21, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 22, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-13 17:00:00+00', '2026-05-13 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (34, 1, 1, NULL, 1, '{"meal": "FULL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 25, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 26, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-15 17:00:00+00', '2026-05-15 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (29, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 21, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 22, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-13 17:10:00+00', '2026-05-13 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (30, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 21, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 22, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-13 17:20:00+00', '2026-05-13 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (31, 1, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 23, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 24, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-14 17:00:00+00', '2026-05-14 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (32, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 23, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 24, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-14 17:10:00+00', '2026-05-14 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (33, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 23, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 24, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-14 17:20:00+00', '2026-05-14 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (35, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 25, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 26, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-15 17:10:00+00', '2026-05-15 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (36, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "NEEDS_OBSERVATION", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 25, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 26, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-15 17:20:00+00', '2026-05-15 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (37, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 27, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-16 17:00:00+00', '2026-05-16 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (38, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 27, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-16 17:10:00+00', '2026-05-16 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (39, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 27, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-16 17:20:00+00', '2026-05-16 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (40, 1, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 28, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-17 17:00:00+00', '2026-05-17 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (41, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 28, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-17 17:10:00+00', '2026-05-17 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (42, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 28, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-17 17:20:00+00', '2026-05-17 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (43, 1, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 29, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 30, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-18 17:00:00+00', '2026-05-18 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (49, 1, 1, NULL, 1, '{"meal": "LITTLE", "mood": "NORMAL", "health": "NORMAL", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 33, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 34, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-20 17:00:00+00', '2026-05-20 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (44, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 29, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 30, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-18 17:10:00+00', '2026-05-18 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (45, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 29, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 30, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-18 17:20:00+00', '2026-05-18 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (46, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 31, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 32, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-19 17:00:00+00', '2026-05-19 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (47, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 31, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 32, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-19 17:10:00+00', '2026-05-19 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (48, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 31, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 32, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-19 17:20:00+00', '2026-05-19 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (50, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 33, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 34, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-20 17:10:00+00', '2026-05-20 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (51, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "NORMAL", "health": "NEEDS_OBSERVATION", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 33, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 34, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-20 17:20:00+00', '2026-05-20 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (52, 1, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 35, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 36, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-21 17:00:00+00', '2026-05-21 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (53, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 35, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 36, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-21 17:10:00+00', '2026-05-21 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (54, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 35, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 36, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-21 17:20:00+00', '2026-05-21 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (55, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 37, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 38, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-22 17:00:00+00', '2026-05-22 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (56, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 37, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 38, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-22 17:10:00+00', '2026-05-22 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (57, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 37, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 38, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-22 17:20:00+00', '2026-05-22 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (58, 1, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 39, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-23 17:00:00+00', '2026-05-23 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (59, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 39, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-23 17:10:00+00', '2026-05-23 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (60, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 39, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-23 17:20:00+00', '2026-05-23 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (61, 1, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 40, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-24 17:00:00+00', '2026-05-24 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (62, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "NORMAL", "health": "NORMAL", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 40, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-24 17:10:00+00', '2026-05-24 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (63, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 40, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-24 17:20:00+00', '2026-05-24 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (69, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 43, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 44, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-26 17:20:00+00', '2026-05-26 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (64, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 41, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 42, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-25 17:00:00+00', '2026-05-25 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (65, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 41, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 42, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-25 17:10:00+00', '2026-05-25 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (66, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "NEEDS_OBSERVATION", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 41, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 42, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-25 17:20:00+00', '2026-05-25 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (67, 1, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 43, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 44, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-26 17:00:00+00', '2026-05-26 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (68, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "실버 건강 스트레칭 체조 🧘‍♀️", "program_id": 43, "start_time": "10:00"}, {"title": "건강 아로마 발 마사지 🦶", "program_id": 44, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-26 17:10:00+00', '2026-05-26 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (70, 1, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 45, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 46, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-27 17:00:00+00', '2026-05-27 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (71, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 45, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 46, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-27 17:10:00+00', '2026-05-27 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (72, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "오감 만족 미술 치료 미술 활동 🎨", "program_id": 45, "start_time": "10:00"}, {"title": "추억 회상 음악 감상 📻", "program_id": 46, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-27 17:20:00+00', '2026-05-27 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (73, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 47, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 48, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-28 17:00:00+00', '2026-05-28 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (74, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 47, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 48, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-28 17:10:00+00', '2026-05-28 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (75, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "정서 원예 치료 꽃꽂이 🌸", "program_id": 47, "start_time": "10:00"}, {"title": "소근육 발달 종이접기 교실 📄", "program_id": 48, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-28 17:20:00+00', '2026-05-28 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (76, 1, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 49, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 50, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-29 17:00:00+00', '2026-05-29 19:30:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (77, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 49, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 50, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-29 17:10:00+00', '2026-05-29 19:45:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (78, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "신나는 실버 노래 교실 🎶", "program_id": 49, "start_time": "10:00"}, {"title": "전통 다도 명상 시간 🍵", "program_id": 50, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-29 17:20:00+00', '2026-05-29 20:00:00+00', '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (83, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 52, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-05-31 17:10:00+00', NULL, '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (79, 1, 1, NULL, 1, '{"meal": "FULL", "mood": "NORMAL", "health": "GOOD", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 51, "start_time": "14:00"}]', '점심 식사 맛있게 다 비우셨고, 손녀 자랑 많이 하심. 인지 치료 때 집중 잘 하셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 순자 어르신의 오늘 소식을 전해드립니다. 오늘 인지 훈련 시간에 다른 어르신들과 도란도란 이야기를 나누며 활발히 참여하셨습니다. 점심도 든든히 드셨고 식사 후 혈당 수치도 매우 안정적으로 조절되었습니다. 👍 오후에는 손녀분 이야기를 하시며 얼굴 가득 밝은 미소를 지으셨습니다. 즐거운 저녁 되세요. 😊", "index": 1, "label": "B"}, {"text": "순자 어르신 보호자님께 인사드립니다. 🌸 오늘 어르신께서는 인지 퍼즐 훈련을 하시며 높은 성취감을 느끼셨습니다. 🧩 요즘 손녀분 생각을 많이 하시는지 관련 추억담을 들려주시는 목소리가 무척 활기찼습니다. 식사도 잘 하셨고 건강 상태도 이상 없이 아주 양호하십니다. 편안한 밤 보내시기 바랍니다. 💖", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 순자 어르신께서는 오전 인지치료 프로그램에 참여하셔서 예쁜 색칠공부를 하셨습니다. 🎨 집중하시는 모습이 참 아름다우셨어요. 점심 식사로 나온 소고기미역국을 무척 좋아하셔서 한 그릇을 깨끗이 다 비우셨습니다. 😊 오후에는 손녀분 자랑을 끊임없이 하시는 모습에서 깊은 사랑과 애정을 느낄 수 있었습니다. 행복하고 평온한 하루를 보내셨습니다. 💕', 'SENT', false, '2026-05-30 17:00:00+00', NULL, '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (80, 2, 1, NULL, 1, '{"meal": "FULL", "mood": "GOOD", "health": "NORMAL", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 51, "start_time": "14:00"}]', '혈압 정상 유지됨. 노래 교실에서 마이크 잡고 박수치며 즐겁게 부르셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 🌸 복남 어르신의 오늘 소식입니다. 오늘 노래교실에서 옛 추억에 잠겨 함박웃음을 지으시며 노래를 열정적으로 소화하셨습니다. 🎤 지켜보는 요양사들에게도 큰 웃음을 선물해 주셨어요. 혈압과 체온 모두 정상이시며 기분이 매우 좋으셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 보호자님 안녕하세요. 😊 어르신께서는 오늘 노래 부르기 활동에서 남다른 목소리로 다 함께 노래를 부르는 등 활기찬 모습이 두드러진 하루였습니다. 🎶 고혈압 관리 약도 정확하게 챙겨 드셨으며, 편안하게 저녁 휴식을 맞이하고 계십니다. 감사합니다. ✨", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 😊 오늘 복남 어르신께서는 오후 노래교실에서 가장 앞장서서 활약해 주셨습니다. 🎶 평소 즐겨 부르시던 노래가 흘러나오자 마이크를 두 손으로 잡고 박수치며 노래를 불러주셔서 교실 분위기가 아주 밝아졌습니다. 혈압도 정상적으로 잘 조절되고 있으며, 컨디션도 최상이십니다. 기분 좋은 하루 보내세요! 👍', 'SENT', false, '2026-05-30 17:10:00+00', NULL, '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (81, 3, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "NEEDS_OBSERVATION", "medication": "DONE"}', '[{"title": "주말 명작 극장 시네마 데이 🎬", "program_id": 51, "start_time": "14:00"}]', '침상에서 가벼운 스트레칭 도와드렸습니다. 휠체어를 타고 거실에서 티비 보시며 미소를 지으셨습니다. 식사는 보통이었습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 정호 어르신의 소식입니다. ✨ 오늘 오전에는 침대 위에서 근육이 굳지 않도록 가벼운 전신 이완 스트레칭을 꼼꼼하게 지원해 드렸습니다. 오후에는 휠체어에 탑승하셔 거실 넓은 공간에서 편하게 휴식을 취하시고, 정겨운 TV 방송을 감상하셨습니다. 식사와 투약도 잘 완료하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 소식 드립니다. 😊 어르신께서는 오늘 침상 휴식을 넉넉히 취하시며 부드러운 손마사지와 스트레칭 치료를 편안히 즐기셨습니다. 오후 간식 시간 즈음에는 휠체어를 타고 창가를 바라보며 바깥 풍경을 조용히 관찰하셨습니다. 📻 소화 상태와 체온 모두 정상 범주에 있습니다. 편안한 시간 보내세요. 🌸", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 😊 오늘 정호 어르신께서는 침상에서 요양사의 지도 아래 손목과 다리 근육의 굳어짐을 방지하는 부드러운 침상 관절 스트레칭을 편안하게 받으셨습니다. 🧘‍♂️ 오후에는 안전하게 휠체어로 거실로 이동하셔서 어르신들과 함께 재미있는 텔레비전을 시청하며 환하게 미소를 보여주셨습니다. 📺 식사도 한 공기 보통 양으로 편안하게 다 소화하셨습니다. 평온한 하루를 보내셨습니다. 🍀', 'SENT', false, '2026-05-30 17:20:00+00', NULL, '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (82, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 52, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-05-31 17:00:00+00', NULL, '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (84, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "원내 가벼운 휴식 및 개별 면회 🍀", "program_id": 52, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-05-31 17:20:00+00', NULL, '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (85, 1, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 53, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 54, "start_time": "14:00"}]', '체조 동작을 잘 따라 하셨고, 혈당 조절도 안정적입니다. 간식 단호박죽을 좋아하셨어요.', 'POLITE', '[{"text": "보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 오늘 순자 어르신께서는 실버 체조 활동으로 하루를 활기차게 시작하셨습니다. 🧘‍♀️ 굳어있던 몸을 쭉쭉 펴시며 시원해하셨어요. 당뇨식 간식으로 챙겨드린 단호박죽을 참 맛있게 드셔 주셔서 바라보는 직원들도 기뻤습니다. 혈당도 규칙적으로 잘 검사 중입니다. 💖", "index": 1, "label": "B"}, {"text": "순자 어르신의 하루 소식입니다. 😊 오늘 어르신께서는 아침 실버 스트레칭에 성실하게 함께하셨습니다. 당뇨 예방을 위해 철저한 간식 제어가 이루어졌고, 만족스럽게 단호박죽을 즐기셨습니다. 🥣 건강 수치 모두 양호하시며 평온하게 휴식을 취하고 계십니다. 따뜻한 하루 보내세요! ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요! ☀️ 오늘 순자 어르신께서는 실버 체조 시간에 어깨와 팔을 가볍게 움직이시며 적극적으로 참여해 주셨습니다. 💪 혈당도 당뇨 기준치 이내로 잘 유지되어 건강 상태가 매우 우수합니다. 간식으로 나온 달콤한 단호박죽을 크게 좋아하셔서 맛있게 드셨습니다. 😊 늘 건강에 힘쓰고 있으니 안심하셔도 좋습니다. 🍀', 'SENT', false, '2026-06-01 17:00:00+00', NULL, '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (86, 2, 1, NULL, 1, '{"meal": "NORMAL", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 53, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 54, "start_time": "14:00"}]', '원예 치료 시간에 화분에 흙을 잘 채워주셨습니다. 혈압도 안정적이고 점심 생선구이를 다 드셨습니다.', 'POLITE', '[{"text": "안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀", "index": 0, "label": "A"}, {"text": "보호자님 안녕하세요! 😊 오늘 복남 어르신은 요양원 마당의 작은 식물 화분을 꾸미는 원예 미술 시간에 참여하셨습니다. 🌱 초록 흙을 만지며 예전 정원을 가꾸던 때가 생각나신다며 밝게 웃으셨습니다. 식사도 생선 구이와 함께 다 드셨고 혈압약 복용도 완수하셨습니다. 💖", "index": 1, "label": "B"}, {"text": "복남 어르신 소식 전해드립니다. ✨ 오늘 어르신은 원예 프로그램에서 흙과 식물을 보며 마음의 치유를 받는 평화로운 시간을 보냈습니다. 🪴 입맛이 좋으셨는지 생선구이를 남김없이 드시며 식사도 성공적으로 마치셨습니다. 신체 기능 및 혈압 모두 모니터링상 안정 상태이십니다. 🌟", "index": 2, "label": "C"}]', 0, false, '안녕하세요 보호자님! 오늘 복남 어르신께서는 원예 치료 꽃꽂이 활동에 매우 섬세하게 참여해 주셨습니다. 🌸 화분에 조심스럽게 흙을 채우고 예쁜 꽃을 정성껏 심어주셨어요. 점심 식사로 차려진 생선구이 반찬도 뼈를 잘 발라 무척 맛있게 드셨습니다. 😊 혈압 수치도 지극히 양호하며 평온히 잘 계십니다. 🍀', 'SENT', false, '2026-06-01 17:10:00+00', NULL, '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
INSERT INTO public.notice (id, resident_id, author_id, root_notice_id, version, structured_status, participated_programs, raw_memo, tone, ai_generated_texts, selected_draft_index, is_refined, final_polished_text, status, is_edited, sent_at, read_at, created_at, updated_at, deleted_at, memo_lang) VALUES (87, 3, 1, NULL, 1, '{"meal": "LITTLE", "mood": "GOOD", "health": "GOOD", "medication": "DONE"}', '[{"title": "치매 예방 인지 훈련 🧩", "program_id": 53, "start_time": "10:00"}, {"title": "두뇌 자극 보드게임 🎲", "program_id": 54, "start_time": "14:00"}]', '관절 마사지 도중 시원해 하셨고, 휠체어를 타고 다도 명상 프로그램에 참여하여 음악을 잘 들으셨습니다.', 'POLITE', '[{"text": "보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖", "index": 0, "label": "A"}, {"text": "안녕하세요 보호자님! 😊 오늘 정호 어르신은 휠체어를 이용하여 찻잔의 온도와 음악을 공유하는 다도 프로그램에 차분히 동행하셨습니다. 프로그램 진행 내내 평화롭게 클래식 음율을 감상하셨습니다. 🎶 물리치료사의 세심한 관절 마사지도 제공해 드렸는데 미소를 띠며 호응해 주셨습니다. 건강한 저녁 되시기 바랍니다. 🍀", "index": 1, "label": "B"}, {"text": "정호 어르신 보호자님께 안부 전합니다. 🌸 오늘 어르신은 침상 위에서 개인 어깨 마사지 케어를 받으시며 시원한 휴식을 즐기셨습니다. 오후 프로그램에는 편안한 휠체어를 사용해 차를 우려 마시며 전통 음악을 함께 경청하셨습니다. 식욕과 소화 모두 양호하며 규칙적인 케어가 이어졌습니다. ✨", "index": 2, "label": "C"}]', 0, false, '보호자님 안녕하세요. 🍵 오늘 정호 어르신께서는 굳어 있는 어깨와 다리 근육을 풀어드리는 침상 관절 마사지 시간에 무척 시원해하시며 편안한 표정을 지어주셨습니다. 😊 오후에는 휠체어로 다도 명상실로 이동하여 따뜻한 찻잔의 향을 느끼시며 조용히 흐르는 한옥 음악을 귀 기울여 들으셨습니다. 식사도 잘 소화하셨고 건강히 지내고 계십니다. 💖', 'SENT', false, '2026-06-01 17:20:00+00', NULL, '2026-06-01 10:37:41.867648+00', '2026-06-01 10:37:41.867648+00', NULL, 'ko');
