INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (1, 1, '2026-05-01', '10:00:00', '신나는 실버 노래 교실 🎶', '추억의 가요와 민요를 따라 부르며 스트레스를 해소하고 폐활량을 높였습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (2, 1, '2026-05-01', '14:00:00', '전통 다도 명상 시간 🍵', '따뜻한 녹차와 함께 명상을 하며 한 주의 긴장을 풀고 차분히 마음을 다스렸습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (3, 1, '2026-05-02', '14:00:00', '주말 명작 극장 시네마 데이 🎬', '어르신들이 좋아하시는 고전 영화를 대형 스크린으로 상영하고 간식을 즐겼습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (4, 1, '2026-05-03', '14:00:00', '원내 가벼운 휴식 및 개별 면회 🍀', '한 주를 마무리하며 클래식 음악을 감상하고, 개별 휴식과 보호자 면회를 지원했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (5, 1, '2026-05-04', '10:00:00', '치매 예방 인지 훈련 🧩', '어르신들의 뇌 활동을 자극하고 집중력을 높이는 퍼즐 및 퍼즐 게임을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (6, 1, '2026-05-04', '14:00:00', '두뇌 자극 보드게임 🎲', '집중력과 전략적 사고를 유도하는 가벼운 카드 매칭 및 보드게임을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (7, 1, '2026-05-05', '10:00:00', '실버 건강 스트레칭 체조 🧘‍♀️', '전신 근육을 이완하고 혈액 순환을 돕는 가벼운 맨손 체조 활동을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (8, 1, '2026-05-05', '14:00:00', '건강 아로마 발 마사지 🦶', '아로마 오일을 사용해 피로를 풀고 어르신들의 숙면을 돕는 발 마사지 치료를 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (9, 1, '2026-05-06', '10:00:00', '오감 만족 미술 치료 미술 활동 🎨', '색종이와 점토를 활용해 소근육 발달과 창의성을 자극하는 창작 활동을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (10, 1, '2026-05-06', '14:00:00', '추억 회상 음악 감상 📻', '어린 시절 불렀던 옛 동요와 흘러간 옛 노래를 들으며 정서적 안정을 유도했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (11, 1, '2026-05-07', '10:00:00', '정서 원예 치료 꽃꽂이 🌸', '허브 식물을 심고 가꾸며 심리적 안정과 자연 교감을 돕는 활동을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (12, 1, '2026-05-07', '14:00:00', '소근육 발달 종이접기 교실 📄', '학, 배, 비행기 등 종이 접기 활동을 통해 눈과 손의 협응력을 향상했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (13, 1, '2026-05-08', '10:00:00', '신나는 실버 노래 교실 🎶', '추억의 가요와 민요를 따라 부르며 스트레스를 해소하고 폐활량을 높였습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (14, 1, '2026-05-08', '14:00:00', '전통 다도 명상 시간 🍵', '따뜻한 녹차와 함께 명상을 하며 한 주의 긴장을 풀고 차분히 마음을 다스렸습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (15, 1, '2026-05-09', '14:00:00', '주말 명작 극장 시네마 데이 🎬', '어르신들이 좋아하시는 고전 영화를 대형 스크린으로 상영하고 간식을 즐겼습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (16, 1, '2026-05-10', '14:00:00', '원내 가벼운 휴식 및 개별 면회 🍀', '한 주를 마무리하며 클래식 음악을 감상하고, 개별 휴식과 보호자 면회를 지원했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (17, 1, '2026-05-11', '10:00:00', '치매 예방 인지 훈련 🧩', '어르신들의 뇌 활동을 자극하고 집중력을 높이는 퍼즐 및 퍼즐 게임을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
