INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (93, 1, '2026-06-24', '10:00:00', '오감 만족 미술 치료 미술 활동 🎨', '색종이와 점토를 활용해 소근육 발달과 창의성을 자극하는 창작 활동을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (94, 1, '2026-06-24', '14:00:00', '추억 회상 음악 감상 📻', '어린 시절 불렀던 옛 동요와 흘러간 옛 노래를 들으며 정서적 안정을 유도했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (95, 1, '2026-06-25', '10:00:00', '정서 원예 치료 꽃꽂이 🌸', '허브 식물을 심고 가꾸며 심리적 안정과 자연 교감을 돕는 활동을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (96, 1, '2026-06-25', '14:00:00', '소근육 발달 종이접기 교실 📄', '학, 배, 비행기 등 종이 접기 활동을 통해 눈과 손의 협응력을 향상했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (97, 1, '2026-06-26', '10:00:00', '신나는 실버 노래 교실 🎶', '추억의 가요와 민요를 따라 부르며 스트레스를 해소하고 폐활량을 높였습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (98, 1, '2026-06-26', '14:00:00', '전통 다도 명상 시간 🍵', '따뜻한 녹차와 함께 명상을 하며 한 주의 긴장을 풀고 차분히 마음을 다스렸습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (99, 1, '2026-06-27', '14:00:00', '주말 명작 극장 시네마 데이 🎬', '어르신들이 좋아하시는 고전 영화를 대형 스크린으로 상영하고 간식을 즐겼습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (100, 1, '2026-06-28', '14:00:00', '원내 가벼운 휴식 및 개별 면회 🍀', '한 주를 마무리하며 클래식 음악을 감상하고, 개별 휴식과 보호자 면회를 지원했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (101, 1, '2026-06-29', '10:00:00', '치매 예방 인지 훈련 🧩', '어르신들의 뇌 활동을 자극하고 집중력을 높이는 퍼즐 및 퍼즐 게임을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
INSERT INTO public.program (id, facility_id, program_date, start_time, title, description, created_at, updated_at, deleted_at) VALUES (102, 1, '2026-06-29', '14:00:00', '두뇌 자극 보드게임 🎲', '집중력과 전략적 사고를 유도하는 가벼운 카드 매칭 및 보드게임을 진행했습니다.', '2026-06-01 10:37:41.759075+00', '2026-06-01 10:37:41.759075+00', NULL);
